import { useEffect, useState } from "react";
import axios from "axios";
import { Link, useParams } from "react-router-dom";

export default function ProjectDetails() {
  const { projectId } = useParams();
  const [project, setProject] = useState(null);
  const token = localStorage.getItem("token");

  const getProjectDetails = async () => {
    try {
      const res = await axios.get(`http://localhost:3004/projects/${projectId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setProject(res.data);
    } catch (error) {
      console.log("ERROR:", error.response || error.message);
    }
  };

  useEffect(() => {
    getProjectDetails();
  }, [projectId]);

  if (!project) return <p>Chargement...</p>;

  return (
    <div>
      <h1>Détails du projet</h1>
      <p><strong>Nom :</strong> {project.nom}</p>
      <p><strong>Description :</strong> {project.description}</p>
      <p><strong>Statut :</strong> {project.statut}</p>

      <hr />

      <h3>Gestion du projet</h3>

      <div style={{ display: "flex", gap: "12px", flexWrap: "wrap" }}>
        <Link to={`/projects/${projectId}/tasks`}>Tasks</Link>
        <Link to={`/projects/${projectId}/kanban`}>Kanban</Link>
        <Link to={`/projects/${projectId}/reports`}>Reports</Link>
      </div>
    </div>
  );
}
